static void AddHuffmanBits(unsigned symbol, unsigned length,
                           unsigned char *bp, unsigned char **out,
                           size_t *outsize)
{
    /* TODO(lode): make more efficient (add more bits at once). */
    unsigned i;
    for (i = 0; i < length; i++)
