        unsigned bit = (symbol >> (length - i - 1)) & 1;
        if (*bp == 0)
            ZOPFLI_APPEND_DATA(0, out, outsize);
        (*out)[*outsize - 1] |= bit << *bp;
        *bp = (*bp + 1) & 7;
    }
}

static void AddBits(unsigned symbol, unsigned length,
